const allNpmData = {{apiNode_851.output}};
const packageName = {{forLoopNode_330.output.currentValue.name}};
const packageVersion = {{forLoopNode_330.output.currentValue.version}};
const osvData = {{apiNode_948.output}};

// Find the correct package from the array by matching name
const npmData = Array.isArray(allNpmData) 
  ? allNpmData.find(p => p.name === packageName) 
  : allNpmData;

// 1. ABANDONMENT CHECK
const tmpField = npmData?._npmOperationalInternal?.tmp || "";
const tsMatch = tmpField.match(/_(\d{13})_/);
const lastPublished = tsMatch ? new Date(parseInt(tsMatch[1])) : null;

const daysSinceUpdate = lastPublished
  ? Math.floor((Date.now() - lastPublished.getTime()) / (1000 * 60 * 60 * 24))
  : 9999;

const isAbandoned = daysSinceUpdate > 365;

// 2. MAINTAINER CHECK
const maintainers = npmData?.maintainers || [];
const maintainerCount = maintainers.length;
const singleMaintainer = maintainerCount === 1;

// 3. CVE CHECK
const vulns = osvData?.vulns || [];
const vulnCount = vulns.length;
const hasVulns = vulnCount > 0;

const vulnDetails = vulns.map(v => ({
  id: v.id,
  summary: v.summary || "No summary available",
  severity: v.database_specific?.severity || "UNKNOWN"
}));

// 4. LICENSE CHECK
const license = npmData?.license || "UNKNOWN";
const riskyLicenses = ["GPL-2.0", "GPL-3.0", "AGPL-3.0", "LGPL-2.1"];
const hasRiskyLicense = riskyLicenses.includes(license);

// 5. RISK SCORE
let riskScore = 0;
const riskFlags = [];

if (isAbandoned) {
  riskScore += 30;
  riskFlags.push(`Abandoned — last updated ${daysSinceUpdate} days ago`);
}
if (singleMaintainer) {
  riskScore += 20;
  riskFlags.push(`Single maintainer (bus factor = 1)`);
}
if (hasVulns) {
  riskScore += vulnCount * 15;
  riskFlags.push(`${vulnCount} known CVE(s) found`);
}
if (hasRiskyLicense) {
  riskScore += 20;
  riskFlags.push(`Risky license: ${license}`);
}

riskScore = Math.min(riskScore, 100);

// 6. RISK LEVEL
let riskLevel;
if (riskScore >= 70) riskLevel = "CRITICAL";
else if (riskScore >= 40) riskLevel = "HIGH";
else if (riskScore >= 20) riskLevel = "MEDIUM";
else riskLevel = "LOW";

return {
  package: packageName,
  version: packageVersion,
  riskScore,
  riskLevel,
  riskFlags,
  details: {
    lastPublished: lastPublished?.toISOString() || "Unknown",
    daysSinceUpdate,
    maintainerCount,
    license,
    vulnCount,
    vulns: vulnDetails
  }
};

const pkg = {{triggerNode_1.output.file_content}};
const fileType = {{agentClassifierNode_876.output.class}};

let packages = [];

if (fileType === "npm" || typeof pkg === "object") {
  // npm package.json
  const deps = {
    ...(pkg.dependencies || {}),
    ...(pkg.devDependencies || {})
  };
  packages = Object.entries(deps).map(([name, version]) => ({
    name: String(name),
    version: String(version).replace(/[\^~]/g, "")
  }));

} else if (fileType === "pip" || typeof pkg === "string") {
  // requirements.txt - comes as plain text
  packages = pkg
    .split("\n")
    .map(line => line.trim())
    .filter(line => line && !line.startsWith("#"))
    .map(line => {
      const [name, version] = line.split("==");
      return {
        name: name.trim(),
        version: version ? version.trim() : "latest"
      };
    });
}

return { packages, fileType };

